(() => {
  const data = {
    "patientId": "MRN-200",
    "dischargeDate": "2026-07-10",
    "dischargeStatus": "Routine",
    "destination": "Home",
    "destinationAddress": "22 Cedar Test Avenue",
    "livesAlone": true,
    "stairsAtHome": "1-5 steps",
    "caregiverName": "David Vance",
    "caregiverPhone": "555-888-1234",
    "caregiverRelationship": "Spouse",
    "caregiverAvailableOnDischarge": true,
    "transportType": "Self/Family",
    "medicationReconciliationComplete": true,
    "newMedications": "",
    "insuranceVerified": true,
    "followUpType": "Cardiology",
    "followUpDate": "2026-07-17",
    "followUpBooked": true,
    "equipmentNeeded": ["Walker"],
    "homeHealthOrdered": false,
    "communityServicesReferral": false,
    "physicianSignature": true,
    "socialWorkerSignature": true
  };

  const setVal = (selector, value) => {
    const el = document.querySelector(selector);
    if (!el) return;
    if (el.type === 'checkbox') {
      if (el.checked !== value) {
        el.click();
      }
    } else if (el.tagName === 'SELECT') {
      el.value = value;
      el.dispatchEvent(new Event('change', { bubbles: true }));
    } else {
      const setter = Object.getOwnPropertyDescriptor(window.HTMLInputElement.prototype, 'value').set || 
                     Object.getOwnPropertyDescriptor(window.HTMLTextAreaElement.prototype, 'value').set;
      setter.call(el, value);
      el.dispatchEvent(new Event('input', { bubbles: true }));
    }
  };

  setVal('select[name="patientId"]', data.patientId);
  setVal('input[name="dischargeDate"]', data.dischargeDate);
  setVal('select[name="dischargeStatus"]', data.dischargeStatus);
  setVal('select[name="destination"]', data.destination);
  setVal('input[name="destinationAddress"]', data.destinationAddress);
  setVal('input[name="livesAlone"]', data.livesAlone);
  setVal('select[name="stairsAtHome"]', data.stairsAtHome);
  setVal('input[name="caregiverName"]', data.caregiverName);
  setVal('input[name="caregiverPhone"]', data.caregiverPhone);
  setVal('input[name="caregiverRelationship"]', data.caregiverRelationship);
  setVal('input[name="caregiverAvailableOnDischarge"]', data.caregiverAvailableOnDischarge);
  setVal('select[name="transportType"]', data.transportType);
  setVal('input[name="medicationReconciliationComplete"]', data.medicationReconciliationComplete);
  setVal('textarea[name="newMedications"]', data.newMedications);
  setVal('input[name="insuranceVerified"]', data.insuranceVerified);
  setVal('input[name="followUpType"]', data.followUpType);
  setVal('input[name="followUpDate"]', data.followUpDate);
  setVal('input[name="followUpBooked"]', data.followUpBooked);

  // Equipment needed is a multiple select
  const equipSelect = document.querySelector('select[name="equipmentNeeded"]');
  if (equipSelect) {
    Array.from(equipSelect.options).forEach(opt => {
      opt.selected = data.equipmentNeeded.includes(opt.value);
    });
    equipSelect.dispatchEvent(new Event('change', { bubbles: true }));
  }

  setVal('input[name="homeHealthOrdered"]', data.homeHealthOrdered);
  setVal('input[name="communityServicesReferral"]', data.communityServicesReferral);
  setVal('input[name="physicianSignature"]', data.physicianSignature);
  setVal('input[name="socialWorkerSignature"]', data.socialWorkerSignature);

  return "Done";
})()
